func:
// Formato nuevo recibido desde la ESP32 base:
// seq,t_ms,roll,pitch,g_lat,g_lon,yaw_rate,lat,lon,gps_speed_mps,
// gps_course_deg,gps_sats,gps_hdop,gps_fix,rssi,snr,lost,total

let line = msg.payload.toString().trim();

if (!line) return null;

if (
    line.startsWith("#") ||
    line.startsWith("seq") ||
    line.startsWith("===") ||
    line.startsWith("LoRa") ||
    line.startsWith("ERROR") ||
    line.startsWith("ets") ||
    line.startsWith("rst:")
) {
    return null;
}

let p = line.split(",");

if (p.length < 18) {
    return null;
}

let data = {
    seq: Number(p[0]),
    t_ms: Number(p[1]),
    roll: Number(p[2]),
    pitch: Number(p[3]),
    g_lat: Number(p[4]),
    g_lon: Number(p[5]),
    yaw_rate: Number(p[6]),
    lat: Number(p[7]),
    lon: Number(p[8]),
    gps_speed_mps: Number(p[9]),
    gps_course_deg: Number(p[10]),
    gps_sats: Number(p[11]),
    gps_hdop: Number(p[12]),
    gps_fix: Number(p[13]),
    rssi: Number(p[14]),
    snr: Number(p[15]),
    lost: Number(p[16]),
    total: Number(p[17])
};

if (
    Number.isNaN(data.seq) ||
    Number.isNaN(data.roll) ||
    Number.isNaN(data.pitch) ||
    Number.isNaN(data.rssi)
) {
    return null;
}

msg.payload = data;
return msg;

msg.payload = Number(msg.payload.g_lat);
msg.topic = "G lateral";
return msg;

msg.payload = Number(msg.payload.g_lon);
msg.topic = "G longitudinal";
return msg;

msg.payload = Number(msg.payload.yaw_rate);
msg.topic = "Yaw rate";
return msg;

msg.payload = Number(msg.payload.lost);
msg.topic = "Paquetes perdidos";
return msg;

msg.payload = Number(msg.payload.gps_fix) === 1 ? "FIX GPS" : "SIN FIX";
msg.topic = "Estado GPS";
return msg;

msg.payload = Number(msg.payload.gps_sats);
msg.topic = "Satélites GPS";
return msg;

let fix = Number(msg.payload.gps_fix);
let hdop = Number(msg.payload.gps_hdop);

msg.payload = fix === 1 ? hdop : 10;
msg.topic = "HDOP";
return msg;

let fix = Number(msg.payload.gps_fix);
let v = Number(msg.payload.gps_speed_mps);

msg.payload = fix === 1 ? v : 0;
msg.topic = "Velocidad GPS";
return msg;

let fix = Number(msg.payload.gps_fix);
let lat = Number(msg.payload.lat);

msg.payload = fix === 1 ? lat.toFixed(6) : "Sin señal";
msg.topic = "Latitud";
return msg;

let fix = Number(msg.payload.gps_fix);
let lon = Number(msg.payload.lon);

msg.payload = fix === 1 ? lon.toFixed(6) : "Sin señal";
msg.topic = "Longitud";
return msg;

let fix = Number(msg.payload.gps_fix);
let course = Number(msg.payload.gps_course_deg);

msg.payload = fix === 1 ? course : 0;
msg.topic = "Rumbo GPS";
return msg;
